class Command:
    """Base class for all commands."""

    name = "base"

    def execute(self, context):
        """Execute this command with the given context."""
        raise NotImplementedError

    def undo(self, context):
        """Undo this command."""
        pass

    def describe(self):
        return f"Command({self.name})"

