from .base import Command


class CreateCmd(Command):
    """Command to create a resource."""
    name = "create"

    def __init__(self, resource_type, data):
        self.resource_type = resource_type
        self.data = data
        self._created_id = None

    def execute(self, context):
        self._created_id = len(context.get("store", {}))
        store = context.setdefault("store", {})
        store[self._created_id] = {"type": self.resource_type, **self.data}
        return {"id": self._created_id, "status": "created"}

    def undo(self, context):
        store = context.get("store", {})
        if self._created_id in store:
            del store[self._created_id]

