from .base import Command


class UpdateCmd(Command):
    """Command to update a resource."""
    name = "update"

    def __init__(self, resource_id, changes):
        self.resource_id = resource_id
        self.changes = changes
        self._old_data = None

    def execute(self, context):
        store = context.get("store", {})
        if self.resource_id not in store:
            return {"status": "not_found"}
        self._old_data = dict(store[self.resource_id])
        store[self.resource_id].update(self.changes)
        return {"status": "updated"}

    def undo(self, context):
        if self._old_data is not None:
            store = context.get("store", {})
            store[self.resource_id] = self._old_data

