from .base import Command


class CommandDispatcher:
    """Dispatches commands with context."""

    def __init__(self, context=None):
        self._context = context or {}
        self._handlers = {}

    def register(self, name, handler):
        if not isinstance(handler, Command):
            raise TypeError(f"Expected Command, got {type(handler).__name__}")
        self._handlers[name] = handler

    def dispatch(self, command):
        """Execute a command with the dispatcher's context."""
        if not isinstance(command, Command):
            raise TypeError(f"Expected Command, got {type(command).__name__}")
        return command.execute(self._context)

    def dispatch_by_name(self, name):
        handler = self._handlers.get(name)
        if handler is None:
            raise KeyError(f"No handler for: {name}")
        return handler.execute(self._context)

