from .base import Command


class CommandValidator:
    """Validate commands before execution."""

    def __init__(self):
        self._rules = {}

    def add_rule(self, command_name, rule_func):
        self._rules[command_name] = rule_func

    def validate(self, command, context):
        """Validate a command against registered rules."""
        if not isinstance(command, Command):
            raise TypeError(f"Expected Command, got {type(command).__name__}")
        rule = self._rules.get(command.name)
        if rule and not rule(command, context):
            return False
        return True

    def validate_and_execute(self, command, context):
        """Validate then execute."""
        if not self.validate(command, context):
            return {"status": "rejected"}
        return command.execute(context)

