class TestAction:
    def test_not_implemented(self):
        a = Action()
        with pytest.raises(NotImplementedError):
            a.perform({})

    def test_describe(self):
        a = Action()
        assert "base" in a.describe()


class TestCreateCmd:
    def test_create(self):
        cmd = CreateCmd("user", {"name": "Alice"})
        env = {"store": {}}
        result = cmd.perform(env)
        assert result["status"] == "created"
        assert len(env["store"]) == 1

    def test_undo_create(self):
        cmd = CreateCmd("user", {"name": "Alice"})
        env = {"store": {}}
        cmd.perform(env)
        cmd.undo(env)
        assert len(env["store"]) == 0


class TestDeleteCmd:
