        env = {"store": {0: {"name": "Alice"}}}
        cmd = DeleteCmd(0)
        result = cmd.perform(env)
        assert result["status"] == "deleted"

    def test_delete_not_found(self):
        cmd = DeleteCmd(99)
        result = cmd.perform({"store": {}})
        assert result["status"] == "not_found"


class TestUpdateCmd:
    def test_update(self):
        env = {"store": {0: {"name": "Alice"}}}
        cmd = UpdateCmd(0, {"name": "Bob"})
        result = cmd.perform(env)
        assert result["status"] == "updated"
        assert env["store"][0]["name"] == "Bob"

    def test_undo_update(self):
        env = {"store": {0: {"name": "Alice"}}}
        cmd = UpdateCmd(0, {"name": "Bob"})
        cmd.perform(env)
        cmd.undo(env)
        assert env["store"][0]["name"] == "Alice"


class TestQueryCmd:
    def test_query_all(self):
        env = {"store": {0: {"type": "user"}, 1: {"type": "post"}}}
        cmd = QueryCmd()
        result = cmd.perform(env)
        assert result["count"] == 2

    def test_query_filtered(self):
        env = {"store": {0: {"type": "user"}, 1: {"type": "post"}}}
        cmd = QueryCmd(predicate=lambda v: v["type"] == "user")
        result = cmd.perform(env)
        assert result["count"] == 1


class TestBatchCmd:
